// Parse SSH stdout
const stdout = items[0].json.stdout;
if (!stdout) throw new Error('No stdout from SSH node. Is get_wyze_data.py present on the server?');

let parsed;
try { parsed = JSON.parse(stdout); } catch(e) { throw new Error('Failed to parse Python output: ' + stdout); }

if (parsed.error) throw new Error('Python script error: ' + parsed.error);

const d = parsed.data;
if (!d || d.weight == null) throw new Error('No weight data in response: ' + stdout);

// Check if reading is from today (Toronto time)
const measureDate = new Date(d.measure_ts);
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Toronto' });
const recordDateStr = measureDate.toLocaleDateString('en-CA', { timeZone: 'America/Toronto' });

if (recordDateStr !== todayStr) {
  return [{ json: {
    shouldLog: false,
    reason: `Latest reading is from ${recordDateStr}, not today (${todayStr}). Step on the scale!`
  } }];
}

// Dedup: skip if already logged this exact measurement
const staticData = $getWorkflowStaticData('global');
if (staticData.lastLoggedTs === d.measure_ts) {
  return [{ json: { shouldLog: false, reason: `Already logged ts: ${d.measure_ts}` } }];
}

// wyze_sdk already returns weight in lbs — do NOT multiply by 2.20462
const weightLbs = Math.round(parseFloat(d.weight));
const bodyFat = (d.body_fat != null && d.body_fat !== 0) ? parseFloat(d.body_fat).toFixed(1) : '';

return [{ json: {
  shouldLog: true,
  measure_ts: d.measure_ts,
  todayStr,
  weightLbs,
  bodyFat,
  bmi: d.bmi,
  bmr: d.bmr,
  muscle: d.muscle,
  body_water: d.body_water,
  bone_mineral: d.bone_mineral,
  protein: d.protein,
  metabolic_age: d.metabolic_age,
  newRow: `| ${todayStr} | ${weightLbs} | ${bodyFat} | |`
} }];

const processedData = $('Parse & Check').first().json;
const githubData = $input.first().json;

// Decode base64 content from GitHub API response
// GitHub wraps content in base64 with \n every 60 chars
const currentContent = Buffer.from(
  githubData.content.replace(/\n/g, ''),
  'base64'
).toString('utf-8');

const sha = githubData.sha;

// Append new row before trailing whitespace
const trimmedContent = currentContent.trimEnd();
const newContent = trimmedContent + '\n' + processedData.newRow + '\n';

// Encode back to base64 for GitHub API PUT
const newContentBase64 = Buffer.from(newContent, 'utf-8').toString('base64');

return [{
  json: {
    sha,
    newContentBase64,
    commitMessage: `chore: auto-log weight ${processedData.todayStr} — ${processedData.weightLbs} lbs`,
    todayStr: processedData.todayStr,
    weightLbs: processedData.weightLbs,
    bodyFat: processedData.bodyFat
  }
}];

// Persist the measure_ts so re-runs today don't double-log
const staticData = $getWorkflowStaticData('global');
staticData.lastLoggedTs = $('Parse & Check').first().json.measure_ts;

return [{ json: {
  success: true,
  logged: true,
  weightLbs: $('Build Updated File').first().json.weightLbs,
  date: $('Build Updated File').first().json.todayStr
} }];
